import Foundation

enum ToolIcons {
    static let icons: [String: String] = [
        "claude-code": "",
        "codex-cli": "",
        "copilot-cli": "",
        "cursor": "",
        "droid": "",
        "kimi": "",
        "kiro": "",
        "opencode": "",
        "pi": "",
        "qoder": "",
    ]

    static func pngData(for toolId: String) -> Data? {
        guard let base64 = icons[toolId] else { return nil }
        return Data(base64Encoded: base64)
    }
}
